   SELECT (IFNULL(MAX(SN), 0)+1) sn from ACCELERATOR WHERE UUID = #{uuid}



	INSERT INTO ACCELERATOR 
		( SN
		  , UUID
		  , XAXIS
		  , YAXIS
		  , ZAXIS
		  , TIMESTAMP
		  , USEYN )
	VALUES ( #{sn}
		  , #{uuid}
		  , #{xaxis}
		  , #{yaxis}
		  , #{zaxis}
		  , #{timestamp}
		  , #{useYn})

mapper.update:

UPDATE ACCELERATOR 
SET SN=#{sn}
	, UUID=#{uuid}
	, XAXIS=#{xaxis}
	, YAXIS=#{yaxis}
	, ZAXIS=#{zaxis}
	, TIMESTAMP=#{timestamp}
	, USEYN=#{useYn}
WHERE SN=#{sn} AND UUID=#{uuid}

mapper.delete:

UPDATE ACCELERATOR 
SET USEYN='N'
WHERE SN=#{sn} AND UUID=#{uuid}

mapper.select:
SELECT
	SN, UUID, XAXIS, YAXIS, ZAXIS, TIMESTAMP, USEYN
FROM ACCELERATOR WHERE USEYN='Y' AND UUID=#{uuid}
